require "ui.window.GUITycoonPrivilegeItem"

local UITycoonToolBar = class("UIToolBar", IGUILayout)

function UITycoonToolBar:onLoad()
    local content = self:getChildWindow("TycoonToolBar-Privilege-Layout", GUIType.Layout)
    content:CleanupChildren()
    self.lvList = IGUIListView.new("TycoonToolBar-Privilege-List", content, nil, Orientation.Horizontal)
    self.lvList:setArea({ 0, 0 }, { 0, 0 }, { 1, 0 }, { 0, 56 })
    self.lvList:setItemSpace(15)
    self:register()
end

function UITycoonToolBar:register()
    self:registerDataCallBack("Privilege", function(data)
        self:createPrivilegeData(data)
    end, JsonBuilderProcessor)

    self:registerDataCallBack("HidePrivilege", function()
        self:hidePrivilege()
    end)
end

function UITycoonToolBar:createPrivilegeData(data)
    local result = {}
    for occIds, time in pairs(data) do
        table.insert(result, { occIds = occIds, time = tonumber(time) })
    end

    table.sort(result, function(a, b)
        return a.time > b.time
    end)
    self.lvList:clearItems()
    for _, item in pairs(result) do
        local guiItem = GUITycoonPrivilegeItem.new()
        guiItem:setData(item.occIds, item.time)
        guiItem.root:SetWidth({ 0, 63 })
        guiItem.root:SetHeight({ 0, 56 })
        self.lvList:addItem(guiItem)
    end

    LuaTimer:cancel(self.timeKey or 0)
    self.timeKey = LuaTimer:scheduleTimer(function()
        for _, guiItem in pairs(self.lvList.items) do
            guiItem:onTick()
        end
    end, 1000)
end

function UITycoonToolBar:hidePrivilege()
    local content = self:getChildWindow("TycoonToolBar-Privilege-Layout", GUIType.Layout)
    content:SetVisible(false)
    LuaTimer:cancel(self.timeKey or 0)
end

return UITycoonToolBar